  ntfy: {
    enabled: boolean;
    topic: string;
    server: string;
  };
  discord: {
    enabled: boolean;
    webhook: string;
  };
  twilio: {
    enabled: boolean;
    toNumber: string;  // User's phone number for SMS alerts
  };
  thresholds: {
    longTaskMinutes: number;
  };
  routing: {
